query:
{
  pods(
    where: {
      managerName: { eq: "" }
      containers_SOME: {
        securityContext: {
          OR: [
            { isSeccompProfileSet: { eq: false } }
            { isSELinuxOptionsSet: { eq: false } }
            { allowPrivilegeEscalation: { eq: true } }
            { runAsNonRoot: { eq: false } }
            { runAsUser_GTE: 1000 }
            { runAsGroup_GTE: 1000 }
            { readOnlyRootFilesystem: { eq: false } }
            { capabilitiesAdd_INCLUDES: "SYS_ADMIN" }
            { privileged: { eq: true } }
            {
              NOT: {
                OR: [
                  { capabilitiesDrop_INCLUDES: "NET_RAW" }
                  { capabilitiesDrop_INCLUDES: "ALL" }
                  { capabilitiesDrop_INCLUDES: "all" }
                ]
              }
            }
          ]
        }
      }
    }
  ) {
    ...AssetFragment
  }
}
